create table dirkspzm32.pps_ruestmatrix_opt_grp (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    opt_grp              varchar2(50 char) not null enable,
    opt_name             varchar2(50 char) not null enable,
    created_date         date not null enable,
    created_login_id     number(*, 0),
    last_change_date     date,
    last_change_login_id number(*, 0),
    beschreibung         varchar2(50 char),
    maxabweichung        number(*, 5) default 0 not null enable
);

alter table dirkspzm32.pps_ruestmatrix_opt_grp
    add constraint pk_pps_ruestmatrix_opt_grp primary key ( opt_grp )
        using index enable;


